#include <bits/stdc++.h>
#define int long long
using namespace std;
const int maxn = 100005;
int mul[maxn];
int qpow (int a, int b, int c) {
	int res = 1;
	a = a % c;
	while (b) {
		if (b & 1) {
			res = res * a % c;
		}
		b >>= 1;
		a = (a * a) % c;
	}
	return res;
}
int c (int n, int m, int p) {
	return (m > n) ? 0 : ((mul[n] * qpow (mul[m], p - 2, p)) % p * qpow (mul[n - m], p - 2, p) % p);
}
int lucas (int n, int m, int p) {
	return (m == 0) ? 1 : c (n % p, m % p, p) * lucas (n / p, m / p, p) % p;
}
signed main() {
	int t;
	cin >> t;
	for (int i = 1; i <= t; i++) {
		int n, m, p;
		cin >> n >> m >> p;
		mul[0] = 1;
		for (int i = 1; i <= p; i++) {
			mul[i] = (mul[i - 1] * i) % p;
		}
		cout << lucas (n + m, n, p) << '\n';
	}
	return 0;
}
